def compute_score() -> tuple[str, float]:
    # Use VLM to check whether both specified bullet points are present on slide 2
    # Find slide 2 screenshot (supports object with attributes or dict with keys)
    slide_2_image = None

    if len(ppt_diff.modified_slides) == 0:
        return 'No modifications detected on slide 2.', 0.0

    for s in modified_ppt_screenshots:
        try:
            s_num = getattr(s, 'slide_number', None)
            if s_num is None and isinstance(s, dict):
                s_num = s.get('slide_number')
            if s_num == 2:
                slide_2_image = s.image_path
                break
        except Exception:
            continue
    if not slide_2_image:
        return 'Slide 2 screenshot not found.', 0.0

    prompt = (
        "Look at this PowerPoint slide (slide 2) and read the bullet points.\n"
        "We expect exactly these two bullet sentences to appear as bullets:\n"
        "1) 'Obesity is defined as excess body fat'\n"
        "2) 'Because body fat is difficult to measure directly, obesity is often measured by body mass index (BMI)'\n"
        "Do both of these exact bullet sentences appear on the slide (ignore indentation issues)? Respond with:\n"
        "- YES if both appear,\n"
        "- PARTIAL if only one appears,\n"
        "- NONE if neither appears."
    )

    try:
        response = vlm_call(images=[slide_2_image], prompt=prompt, temperature=0.1, max_tokens=200)
        resp = str(response).strip()
        if 'YES' in resp and 'PARTIAL' not in resp and 'NONE' not in resp:
            return response, 1.0
        elif 'PARTIAL' in resp or ('YES' in resp and 'NO' in resp):
            return response, 0.5
        elif 'NONE' in resp or 'NO' in resp:
            return response, 0.0
        else:
            return f'Unclear response from VLM: {response}', 0.0
    except Exception as e:
        return f'Error during VLM check: {str(e)}', 0.0

def compute_score() -> tuple[str, float]:
    # Use VLM to check whether the second bullet is indented under the first on slide 2
    slide_2_image = None
    if len(ppt_diff.modified_slides) == 0:
        return 'No modifications detected on slide 2.', 0.0
    for s in modified_ppt_screenshots:
        try:
            if getattr(s, 'slide_number', None) == 2:
                slide_2_image = s.image_path
                break
        except Exception:
            continue
    if not slide_2_image:
        return 'Slide 2 screenshot not found.', 0.0

    prompt = (
        "Look at this PowerPoint slide (slide 2).\n"
        "We expect two bullet sentences:\n"
        "1) 'Obesity is defined as excess body fat'\n"
        "2) 'Because body fat is difficult to measure directly, obesity is often measured by body mass index (BMI)'\n"
        "Is the second sentence presented as an indented sub-bullet under the first (i.e., clearly at a deeper level)?\n"
        "Respond with 'YES' if it is indented as a sub-bullet, 'NO' if it is at the same or higher level, or 'NOT_FOUND' if these bullets are not visible."
    )

    try:
        response = vlm_call(images=[slide_2_image], prompt=prompt, temperature=0.1, max_tokens=200)
        resp = str(response).strip()
        if 'YES' in resp and 'NO' not in resp:
            return response, 1.0
        elif 'NOT_FOUND' in resp:
            return response, 0.0
        elif 'NO' in resp or 'NONE' in resp:
            return response, 0.0
        else:
            return f'Unclear response from VLM: {response}', 0.0
    except Exception as e:
        return f'Error during VLM check: {str(e)}', 0.0

def compute_score():
    # Check for modifications to slide 2 other than bullet/text changes
    extraneous = False
    for s1, s2 in ppt_diff.modified_slides:
        if s1.slide_number == 2 or s2.slide_number == 2:
            # Compare layout_type, notes, element_count
            # Ignore title, since that's often the paragraph.
            if (s1.layout_type != s2.layout_type) or (s1.notes != s2.notes) or (s1.element_count != s2.element_count):
                extraneous = True
    if extraneous:
        return 'Extraneous changes detected on slide 2.', 0.0
    return 'No extraneous changes detected on slide 2.', 1.0
